function outerFunction() {
  let count = 0;
  function innerFunction() {
    count++;
    console.log(count);
  }
  return innerFunction;
}

const myCounter = outerFunction();
myCounter(); // Output: 1
myCounter(); // Output: 2
myCounter(); // Output: 3

const obj = { a: 1, b: 2 };

// This will throw TypeError: obj is not iterable
for (const item of obj) {
  console.log(item);
}

// Correct usage: Object.entries(), Object.keys(), or Object.values()
for (const [key, value] of Object.entries(obj)) {
  console.log(key, value);
}

let someValue: any = "Hello, TypeScript!";
// Using type assertion to tell TypeScript this is a string
let strLength: number = (someValue as string).length;

// Another syntax for type assertion
let strLengthAlternative: number = (<string>someValue).length;

console.log(strLength); // Output: 18
console.log(strLengthAlternative); // Output: 18

interface User {
  name: string;
  age?: number; // age is optional
}

const user: User = { name: 'Alice' };

// This will cause the error because age is undefined
console.log(user.age.toString());

BEGIN TRANSACTION;

-- Transaction 1 locks Row A
UPDATE Products SET Quantity = Quantity - 1 WHERE ProductID = 1;

-- Meanwhile, Transaction 2 locks Row B
UPDATE Products SET Quantity = Quantity - 1 WHERE ProductID = 2;

-- Transaction 1 tries to lock Row B (held by Transaction 2)
UPDATE Products SET Quantity = Quantity - 1 WHERE ProductID = 2;

-- Transaction 2 tries to lock Row A (held by Transaction 1)
UPDATE Products SET Quantity = Quantity - 1 WHERE ProductID = 1;

COMMIT;
